// Validate required fields
const requiredFields = ['idea_description', 'business_context'];
const inputData = items[0].json;

for (const field of requiredFields) {
    if (!inputData[field] || inputData[field].trim() === '') {
        throw new Error(`Missing required field: ${field}`);
    }
}

// Clean and structure data
const processedInput = {
    ideaDescription: inputData.idea_description.trim(),
    businessContext: inputData.business_context.trim(),
    targetAudience: inputData.target_audience || 'General users',
    constraints: inputData.constraints || 'No specific constraints',
    timelinePreference: inputData.timeline_preference || '3-6 months'
};

return [{ json: processedInput }];

// Get the AI response
const aiResponse =
	items[0].json.output ||
	items[0].json.text ||
	items[0].json.response;

if (typeof aiResponse !== 'string') {
	throw new Error('AI response is not a string');
}

// ---------- helpers ----------
function extractSection(label, text) {
	const regex = new RegExp(
		`"${label}"\\s*:\\s*([\\s\\S]*?)(?=\\n\\s*"\\w+"\\s*:|$)`,
		'i'
	);
	const match = text.match(regex);
	return match ? match[1].trim() : '';
}

function normalizeToArray(text) {
	if (!text) return [];

	return text
		.replace(/^[\[\]]/g, '')
		.split(/\n|-•|\*/g)
		.map(v => v.replace(/"|,/g, '').trim())
		.filter(Boolean);
}

function normalizeToString(text) {
	return text
		.replace(/^"/, '')
		.replace(/",?$/, '')
		.trim();
}

// ---------- extraction ----------
try {
	const refinedIdeaRaw = extractSection('refined_idea', aiResponse);
	const alternativesRaw = extractSection('alternatives', aiResponse);
	const coreProblemsRaw = extractSection('core_problems', aiResponse);
	const keyFeaturesRaw = extractSection('key_features', aiResponse);
	const valuePropRaw = extractSection('value_proposition', aiResponse);

	const ideationResult = {
		refined_idea: normalizeToString(refinedIdeaRaw),
		alternatives: normalizeToArray(alternativesRaw),
		core_problems: normalizeToArray(coreProblemsRaw),
		key_features: normalizeToArray(keyFeaturesRaw),
		value_proposition: normalizeToString(valuePropRaw),
	};

	// Final validation
	if (!ideationResult.refined_idea) {
		throw new Error('refined_idea could not be extracted');
	}

	return [
		{
			json: {
				...items[0].json,
				ideationResult,
			},
		},
	];
} catch (error) {
	console.error('Ideation parsing failed:', error);
	throw new Error(`Failed to parse ideation agent response: ${error.message}`);
}

const items = $input.all();
const updatedItems = items.map((item) => {
  const ideationResult = $("Ideation Output")
    .all()
    .find((node) => node?.json?.output === item?.json?.output)
    ?.json?.ideationResult;
  item.json.ideationResult = ideationResult;
  return item;
});
return updatedItems;

// Get the AI response
const aiResponse =
	items[0].json.output ||
	items[0].json.text ||
	items[0].json.response;

try {
	let priorityResult;

	if (typeof aiResponse === 'string') {
		let cleanResponse = aiResponse
			.replace(/```json\s*/gi, '')
			.replace(/```/g, '')
			// Remove trailing commas before } or ]
			.replace(/,\s*([}\]])/g, '$1')
			.trim();

		priorityResult = JSON.parse(cleanResponse);
	} else {
		priorityResult = aiResponse;
	}

	// Validate and normalize scores (1–10)
	const scoreFields = [
		'business_value',
		'user_impact',
		'effort_required',
		'risk_level',
		'market_timing',
		'strategic_fit'
	];

	for (const field of scoreFields) {
		if (
			typeof priorityResult[field] !== 'number' ||
			priorityResult[field] < 1 ||
			priorityResult[field] > 10
		) {
			priorityResult[field] = 5;
		}
	}

	// Recalculate priority score
	const calculatedScore =
		priorityResult.business_value +
		priorityResult.user_impact +
		priorityResult.market_timing +
		priorityResult.strategic_fit -
		((10 - priorityResult.effort_required + 1) +
		 (10 - priorityResult.risk_level + 1));

	priorityResult.calculated_score = Math.round(calculatedScore);

	// Determine priority tier
	if (priorityResult.calculated_score >= 15) {
		priorityResult.priority_tier = 'High';
	} else if (priorityResult.calculated_score >= 8) {
		priorityResult.priority_tier = 'Medium';
	} else {
		priorityResult.priority_tier = 'Low';
	}

	// Ensure arrays exist
	if (!Array.isArray(priorityResult.critical_success_factors)) {
		priorityResult.critical_success_factors = [];
	}

	// Validate ICE score
	if (
		!priorityResult.ice_score ||
		typeof priorityResult.ice_score !== 'object'
	) {
		priorityResult.ice_score = {
			impact: priorityResult.user_impact,
			confidence: 5,
			ease: priorityResult.effort_required
		};
	}

	return [
		{
			json: {
				...items[0].json,
				priorityResult
			}
		}
	];
} catch (error) {
	console.error('Error parsing prioritization response:', error);
	throw new Error(
		`Failed to parse prioritization agent response: ${error.message}`
	);
}

// Get the AI response
const aiResponse =
	items[0].json.output ||
	items[0].json.text ||
	items[0].json.response;

try {
	let roadmapResult;

	if (typeof aiResponse === 'string') {
		let cleanResponse = aiResponse
			.replace(/```json\s*/gi, '')
			.replace(/```/g, '')
			// Remove trailing commas before } or ]
			.replace(/,\s*([}\]])/g, '$1')
			.trim();

		roadmapResult = JSON.parse(cleanResponse);
	} else {
		roadmapResult = aiResponse;
	}

	// Required fields with defaults
	const requiredFields = {
		mvp_features: [],
		mvp_timeline: '3 months',
		phase2_features: [],
		phase2_timeline: '6 months',
		phase3_features: [],
		phase3_timeline: '12 months',
		dependencies: [],
		team_requirements: {},
		mvp_success_metrics: [],
		critical_path: []
	};

	for (const [field, defaultValue] of Object.entries(requiredFields)) {
		if (
			roadmapResult[field] === undefined ||
			roadmapResult[field] === null
		) {
			roadmapResult[field] = defaultValue;
		}
	}

	// Ensure array fields
	const arrayFields = [
		'mvp_features',
		'phase2_features',
		'phase3_features',
		'dependencies',
		'critical_path',
		'parallel_development',
		'mvp_success_metrics',
		'phase2_success_metrics',
		'phase3_success_metrics',
		'go_to_market_timeline'
	];

	for (const field of arrayFields) {
		if (roadmapResult[field] && !Array.isArray(roadmapResult[field])) {
			roadmapResult[field] = [];
		}
	}

	// Ensure nested objects
	if (
		!roadmapResult.team_requirements ||
		typeof roadmapResult.team_requirements !== 'object'
	) {
		roadmapResult.team_requirements = {
			mvp_phase: ['Product Manager', 'Frontend Developer', 'Backend Developer'],
			scaling_phase: ['UI/UX Designer', 'DevOps Engineer', 'QA Engineer']
		};
	}

	if (
		!roadmapResult.resource_allocation ||
		typeof roadmapResult.resource_allocation !== 'object'
	) {
		roadmapResult.resource_allocation = {
			development_effort: '60% MVP, 30% Phase 2, 10% Phase 3',
			design_effort: '40% MVP, 35% Phase 2, 25% Phase 3',
			testing_effort: '50% MVP, 30% Phase 2, 20% Phase 3'
		};
	}

	// Summary
	roadmapResult.roadmap_summary =
		`MVP (${roadmapResult.mvp_timeline}): ` +
		`${roadmapResult.mvp_features.length} features`;

	return [
		{
			json: {
				...items[0].json,
				roadmapResult
			}
		}
	];
} catch (error) {
	console.error('Error parsing roadmap response:', error);
	throw new Error(
		`Failed to parse roadmap agent response: ${error.message}`
	);
}

